export default function Page() {
  return (
    <main style={{ 
      padding: "2rem", 
      fontFamily: "Inter, system-ui, sans-serif",
      maxWidth: "1200px",
      margin: "0 auto",
      lineHeight: 1.6
    }}>
      <div style={{ textAlign: "center", marginBottom: "3rem" }}>
        <h1 style={{ 
          fontSize: "3rem", 
          fontWeight: 700, 
          background: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
          WebkitBackgroundClip: "text",
          WebkitTextFillColor: "transparent",
          margin: 0 
        }}>
          Vanashree Docs
        </h1>
        <p style={{ 
          fontSize: "1.2rem", 
          color: "#666", 
          marginTop: "1rem",
          maxWidth: "600px",
          marginLeft: "auto",
          marginRight: "auto"
        }}>
          Documentation for Vanashree monorepo, UI components, and web apps.
        </p>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr)", gap: "2rem", marginBottom: "4rem" }}>
        <div style={{ 
          padding: "2rem", 
          border: "1px solid #e2e8f0", 
          borderRadius: "12px",
          transition: "all 0.2s"
        }}>
          <h2 style={{ fontSize: "1.5rem", marginBottom: "1rem", color: "#1e293b" }}>🚀 Getting Started</h2>
          <p>Quickstart guides for new contributors and developers.</p>
          <a href="/getting-started" style={{ 
            display: "inline-block", 
            marginTop: "1rem", 
            color: "#667eea", 
            textDecoration: "none",
            fontWeight: 500
          }}>Read docs →</a>
        </div>

        <div style={{ 
          padding: "2rem", 
          border: "1px solid #e2e8f0", 
          borderRadius: "12px" 
        }}>
          <h2 style={{ fontSize: "1.5rem", marginBottom: "1rem", color: "#1e293b" }}>📦 @vanashree/ui</h2>
          <p>Reusable UI components for vanashree-web and other apps.</p>
          <a href="/ui-components" style={{ 
            display: "inline-block", 
            marginTop: "1rem", 
            color: "#667eea", 
            textDecoration: "none",
            fontWeight: 500
          }}>Browse components →</a>
        </div>

        <div style={{ 
          padding: "2rem", 
          border: "1px solid #e2e8f0", 
          borderRadius: "12px" 
        }}>
          <h2 style={{ fontSize: "1.5rem", marginBottom: "1rem", color: "#1e293b" }}>🌐 Architecture</h2>
          <p>Monorepo structure, Turborepo config, and caching strategy.</p>
          <a href="/architecture" style={{ 
            display: "inline-block", 
            marginTop: "1rem", 
            color: "#667eea", 
            textDecoration: "none",
            fontWeight: 500
          }}>View architecture →</a>
        </div>
      </div>

      <div style={{ 
        padding: "2rem", 
        background: "#f8fafc", 
        borderRadius: "12px",
        textAlign: "center"
      }}>
        <h2 style={{ fontSize: "1.5rem", marginBottom: "1rem" }}>Ready to contribute?</h2>
        <p style={{ color: "#64748b", marginBottom: "1.5rem" }}>
          Check out our <a href="/contributing" style={{ color: "#667eea" }}>contribution guide</a> 
          or jump into the codebase.
        </p>
        <div style={{ display: "flex", gap: "1rem", justifyContent: "center", flexWrap: "wrap" }}>
          <a href="https://github.com/your-username/Vanashree-Landing-Page" 
             style={{ 
               padding: "0.75rem 1.5rem", 
               background: "#667eea", 
               color: "white", 
               textDecoration: "none", 
               borderRadius: "8px",
               fontWeight: 500
             }}>
            GitHub Repo
          </a>
          <a href="/contributing" 
             style={{ 
               padding: "0.75rem 1.5rem", 
               border: "2px solid #667eea", 
               color: "#667eea", 
               textDecoration: "none", 
               borderRadius: "8px",
               fontWeight: 500
             }}>
            Contribute
          </a>
        </div>
      </div>
    </main>
  );
}
